mapper.select:
SELECT id, session_scope, role, content, name, created_at
FROM messages
WHERE id = #{id}

SELECT id, session_scope, role, content, name, created_at
FROM (
    SELECT id, session_scope, role, content, name, created_at
    FROM messages
    WHERE session_scope = #{sessionScope}
    ORDER BY created_at DESC
    LIMIT #{limit}
) sub
ORDER BY created_at ASC

SELECT id, session_scope, role, content, name, created_at
FROM messages
WHERE session_scope = #{sessionScope}
  AND role = #{role}
ORDER BY created_at ASC

SELECT COUNT(*)
FROM messages
WHERE session_scope = #{sessionScope}

mapper.update:
UPDATE messages
SET role = #{role},
    content = #{content},
    name = #{name}
WHERE id = #{id}
